// // This module compares two 2-bit numbers and outputs the following signals:
// - Equal (low if A is not equal to B)
// - A_greater (low if A is not greater than B)
// - B_greater (low if B is not greater than A)
module comparator_2bit (
    input [1:0] A,
    input [1:0] B,
    output reg Equal,
    output reg A_greater,
    output reg B_greater
);

always @(*) begin
    Equal = (A == B);
    A_greater = (A > B);
    B_greater = (A < B);
end

endmodule

